  ('elementary-10ced7e2-moex-00341', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依民法第758條規定：「不動產物權，依法律行為而取得、設定、喪失及變更者，非經登記，不生效力。」 此處所謂「法律行為」，不包括下列何者？', '["訂立贈與契約之行為", "移轉所有權之行為", "設定普通抵押權之行為", "拋棄區分地上權之行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00342', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何者並非有權解釋機關？', '["行政機關", "立法機關", "司法機關", "學術機關"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00343', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '買賣因物有瑕疵，而出賣人依法應負擔保之責者，買受人得解除其契約或請求減少其價金。其中「減少價 金」屬於下列何種權利？', '["支配權", "請求權", "形成權", "抗辯權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00344', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於委辦事項，下列敘述何者錯誤？', '["委辦事項係指地方自治團體依法律等規定，在上級政府指揮監督下，執行上級政府交付辦理之非屬該團 體事務，而負其行政執行責任之事項", "委辦係管轄恆定原則之例外", "內政部依建築法及違章建築處理辦法，將有關違章建築之勒令停工通知單，指定由鄉（鎮、市）公所填 發，就是一種委辦事項", "委辦規則依規定應經其他機關核定者，應於核定文送達各該地方行政機關10日內公布或發布"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00345', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '國民大會代表選舉法已於民國95年1月25日廢止，其廢止說明為：「……依……憲法增修條文規定， 憲法本文有關國民大會職權之相關條文已停止適用，是國民大會代表選舉法已無繼續施行之必要……，予 以廢止。」上述法規之廢止原因最符合下列何種情形？', '["機關與其他機關整併，有關法規無保留之必要者", "法規規定之事項已執行完畢，或因情勢變遷，無繼續施行之必要者", "法規因有關法規之廢止或修正致失其依據，而無單獨施行之必要者", "同一事項已定有新法規，並公布或發布施行者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00346', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依我國憲法，下列何者與政府權力之分立無關？', '["內政與外交分立", "行政與考試分立", "起訴與審判分立", "行政與立法分立"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00347', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何者並非我國司法院大法官之職權？', '["宣告命令違憲", "統一解釋法律", "審理憲法機關間之權限爭議", "提出總統、副總統彈劾案"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00348', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '法律規定寺廟若欲處分不動產，須經所屬教會之決議，並呈請該管官署許可，方得處分，此涉及下列何種 基本權之限制？', '["內在信仰自由", "外在宗教自由", "政教分離原則", "良心自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:45+00:00", "source_pdf_sha1": "4cff5c1bfc40", "answer_pdf_sha1": "f53769d74470", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
